for file in files:
    with open(file, "r", encoding="utf-8") as f:
        content = f.read()
    
    footer_idx = content.find('<footer class="')
    if footer_idx == -1:
        continue
        
    new_content = re.sub(r'<div class="footer-social">.*?</div>\s*</div>\s*<!-- Links -->', social_replacement + '\n          </div>\n          <!-- Links -->', content[footer_idx:], flags=re.DOTALL)
    content = content[:footer_idx] + new_content

    footer_idx = content.find('<footer class="') # re-find index as content changed length
    new_content = re.sub(r'<ul class="footer-contact-list">.*?</ul>', contact_replacement, content[footer_idx:], flags=re.DOTALL)
    content = content[:footer_idx] + new_content

    with open(file, "w", encoding="utf-8") as f:
        f.write(content)
print("Updated all files!")
